svg.script:
// Simple script to stagger tspan appearance and position caret
(function(){
  var svg = document.documentElement;
  try {
    var tspans = svg.querySelectorAll('tspan.t');
    var caret = svg.getElementById('caret');
    var baseDelay = 80; // ms per character
    var x = 20; // starting x
    var y = 85; // baseline y
    // Measure and reveal letters one by one
    var idx = 0;
    function showNext(){
      if(idx >= tspans.length) {
        // start blinking
        caret.style.animation = 'blink 1s steps(2, start) infinite';
        return;
      }
      var t = tspans[idx];
      // make visible
      t.style.opacity = '1';
      t.style.animation = 'show 0.04s linear forwards';
      // compute advance by measuring getBBox
      try{
        var bbox = t.getBBox();
        x += bbox.width;
      }catch(e) { x += 18; }
      // move caret
      caret.setAttribute('x', x + 6);
      idx++;
      setTimeout(showNext, baseDelay);
    }
    // Initially hide all characters except spaces
    for(var i=0;i<tspans.length;i++){
      if(tspans[i].textContent === ' ') { tspans[i].style.opacity = 1; }
      else { tspans[i].style.opacity = 0; }
    }
    // place caret at start
    caret.setAttribute('x', 20 + 6);
    caret.setAttribute('y', 30);
    caret.setAttribute('height', 60);
    setTimeout(showNext, 600);
  }catch(e){ /* if scripts disabled or blocked, fallback to static text */ }
})();
